      }
      count := count + n;
      model := Fill(n) + model;
    }

    method unget(src: seq<T>) returns (ok: bool)
      requires Valid()
      modifies this
      ensures Valid()
      ensures ok ==> ReadableModel() == src + old(ReadableModel())
      ensures old(writable_length()) >= |src| ==> ok
